   132→
   133→    template<class Y>
   134→    explicit shared_ptr( Y * p ): px( p ), pn( p ) // Y must be complete
   135→    {
   136→        sofa::pbrpc::detail::sp_enable_shared_from_this( this, p, p );
   137→    }
