   181→    // aliasing
   182→    template< class Y >
   183→    shared_ptr( shared_ptr<Y> const & r, T * p ): px( p ), pn( r.pn ) // never throws
   184→    {
   185→    }
   186→
   187→    template<class Y>
   188→    shared_ptr(shared_ptr<Y> const & r, sofa::pbrpc::detail::static_cast_tag): px(static_cast<element_type *>(r.px)), pn(r.pn)
   189→    {
   190→    }
   191→
   192→    template<class Y>
   193→    shared_ptr(shared_ptr<Y> const & r, sofa::pbrpc::detail::const_cast_tag): px(const_cast<element_type *>(r.px)), pn(r.pn)
   194→    {
   195→    }
   196→
   197→    template<class Y>
   198→    shared_ptr(shared_ptr<Y> const & r, sofa::pbrpc::detail::dynamic_cast_tag): px(dynamic_cast<element_type *>(r.px)), pn(r.pn)
   199→    {
   200→        if(px == 0) // need to allocate new counter -- the cast failed
   201→        {
   202→            pn = sofa::pbrpc::detail::shared_count();
   203→        }
   204→    }
   205→
   206→    template<class Y>
   207→    shared_ptr(shared_ptr<Y> const & r, sofa::pbrpc::detail::polymorphic_cast_tag): px(dynamic_cast<element_type *>(r.px)), pn(r.pn)
   208→    {
   209→        if(px == 0)
   210→        {
   211→            throw std::bad_cast();
   212→        }
   213→    }
   214→
   215→    // assignment
   216→
   217→    shared_ptr & operator=( shared_ptr const & r ) // never throws
   218→    {
   219→        this_type(r).swap(*this);
   220→        return *this;
   221→    }
   222→
   223→    template<class Y>
   224→    shared_ptr & operator=(shared_ptr<Y> const & r) // never throws
   225→    {
   226→        this_type(r).swap(*this);
   227→        return *this;
   228→    }
   229→
   230→
   231→
   232→    void reset() // never throws in 1.30+
   233→    {
   234→        this_type().swap(*this);
   235→    }
   236→
   237→    template<class Y> void reset(Y * p) // Y must be complete
   238→    {
   239→        assert(p == 0 || p != px); // catch self-reset errors
   240→        this_type(p).swap(*this);
   241→    }
   242→
   243→    template<class Y, class D> void reset( Y * p, D d )
   244→    {
   245→        this_type( p, d ).swap( *this );
   246→    }
   247→
   248→    template<class Y, class D, class A> void reset( Y * p, D d, A a )
   249→    {
   250→        this_type( p, d, a ).swap( *this );
   251→    }
   252→
   253→    template<class Y> void reset( shared_ptr<Y> const & r, T * p )
   254→    {
   255→        this_type( r, p ).swap( *this );
   256→    }
   257→
   258→    reference operator* () const // never throws
   259→    {
   260→        assert(px != 0);
   261→        return *px;
   262→    }
   263→
   264→    T * operator-> () const // never throws
   265→    {
   266→        assert(px != 0);
   267→        return px;
   268→    }
   269→
   270→    T * get() const // never throws
   271→    {
   272→        return px;
   273→    }
   274→
   275→// implicit conversion to "bool"
   276→#include <sofa/pbrpc/smart_ptr/detail/operator_bool.hpp>
   277→
   278→    bool unique() const // never throws
   279→    {
   280→        return pn.unique();
   281→    }
   282→
   283→    long use_count() const // never throws
   284→    {
   285→        return pn.use_count();
   286→    }
   287→
   288→    void swap(shared_ptr<T> & other) // never throws
   289→    {
   290→        std::swap(px, other.px);
   291→        pn.swap(other.pn);
   292→    }
   293→
   294→    template<class Y> bool owner_before( shared_ptr<Y> const & rhs ) const
   295→    {
   296→        return pn < rhs.pn;
   297→    }
   298→
   299→    template<class Y> bool owner_before( weak_ptr<Y> const & rhs ) const
   300→    {
   301→        return pn < rhs.pn;
   302→    }
   303→
   304→    void * _internal_get_deleter( std::type_info const & ti ) const
   305→    {
   306→        return pn.get_deleter( ti );
   307→    }
   308→
   309→    bool _internal_equiv( shared_ptr const & r ) const
   310→    {
   311→        return px == r.px && pn == r.pn;
   312→    }
   313→
   314→
   315→private:
   316→
   317→    template<class Y> friend class shared_ptr;
   318→    template<class Y> friend class weak_ptr;
   319→
   320→    T * px;                     // contained pointer
   321→    sofa::pbrpc::detail::shared_count pn;    // reference counter
   322→
   323→};  // shared_ptr
   324→
   325→template<class T, class U> inline bool operator==(shared_ptr<T> const & a, shared_ptr<U> const & b)
   326→{
   327→    return a.get() == b.get();
   328→}
   329→
   330→template<class T, class U> inline bool operator!=(shared_ptr<T> const & a, shared_ptr<U> const & b)
   331→{
   332→    return a.get() != b.get();
   333→}
   334→
   335→template<class T, class U> inline bool operator<(shared_ptr<T> const & a, shared_ptr<U> const & b)
   336→{
   337→    return a.owner_before( b );
   338→}
   339→
   340→template<class T> inline void swap(shared_ptr<T> & a, shared_ptr<T> & b)
   341→{
   342→    a.swap(b);
   343→}
   344→
   345→template<class T, class U> shared_ptr<T> static_pointer_cast(shared_ptr<U> const & r)
   346→{
   347→    return shared_ptr<T>(r, sofa::pbrpc::detail::static_cast_tag());
   348→}
   349→
   350→template<class T, class U> shared_ptr<T> const_pointer_cast(shared_ptr<U> const & r)
   351→{
   352→    return shared_ptr<T>(r, sofa::pbrpc::detail::const_cast_tag());
   353→}
   354→
   355→template<class T, class U> shared_ptr<T> dynamic_pointer_cast(shared_ptr<U> const & r)
   356→{
   357→    return shared_ptr<T>(r, sofa::pbrpc::detail::dynamic_cast_tag());
   358→}
   359→
   360→// get_pointer() enables boost::mem_fn to recognize shared_ptr
   361→
   362→template<class T> inline T * get_pointer(shared_ptr<T> const & p)
   363→{
   364→    return p.get();
   365→}
   366→
   367→// operator<<
   368→
   369→
   370→template<class Y> std::ostream & operator<< (std::ostream & os, shared_ptr<Y> const & p)
   371→{
   372→    os << p.get();
   373→    return os;
   374→}
   375→
   376→template<class E, class T, class Y> std::basic_ostream<E, T> & operator<< (std::basic_ostream<E, T> & os, shared_ptr<Y> const & p)
   377→{
   378→    os << p.get();
   379→    return os;
   380→}
   381→
   382→// get_deleter
   383→
   384→template<class D, class T> D * get_deleter(shared_ptr<T> const & p)
   385→{
   386→    void const * q = p._internal_get_deleter(typeid(D));
   387→    return const_cast<D *>(static_cast<D const *>(q));
   388→}
   389→
   390→
   391→template<class T> inline bool atomic_is_lock_free( shared_ptr<T> const * /*p*/ )
   392→{
   393→    return false;
   394→}
   395→
   396→template<class T> shared_ptr<T> atomic_load( shared_ptr<T> const * p )
   397→{
   398→    sofa::pbrpc::detail::spinlock_pool<2>::scoped_lock lock( p );
   399→    return *p;
   400→}
   401→
   402→template<class T> inline shared_ptr<T> atomic_load_explicit( shared_ptr<T> const * p, ::sofa::pbrpc::memory_order /*mo*/ )
   403→{
   404→    return atomic_load( p );
   405→}
   406→
   407→template<class T> void atomic_store( shared_ptr<T> * p, shared_ptr<T> r )
   408→{
   409→    sofa::pbrpc::detail::spinlock_pool<2>::scoped_lock lock( p );
   410→    p->swap( r );
   411→}
   412→
   413→template<class T> inline void atomic_store_explicit( shared_ptr<T> * p, shared_ptr<T> r, ::sofa::pbrpc::memory_order /*mo*/ )
   414→{
   415→    atomic_store( p, r ); // std::move( r )
   416→}
   417→
   418→template<class T> shared_ptr<T> atomic_exchange( shared_ptr<T> * p, shared_ptr<T> r )
   419→{
   420→    sofa::pbrpc::detail::spinlock & sp = sofa::pbrpc::detail::spinlock_pool<2>::spinlock_for( p );
   421→
   422→    sp.lock();
   423→    p->swap( r );
   424→    sp.unlock();
   425→
   426→    return r; // return std::move( r )
   427→}
   428→
   429→template<class T> shared_ptr<T> atomic_exchange_explicit( shared_ptr<T> * p, shared_ptr<T> r, ::sofa::pbrpc::memory_order /*mo*/ )
   430→{
   431→    return atomic_exchange( p, r ); // std::move( r )
   432→}
   433→
   434→template<class T> bool atomic_compare_exchange( shared_ptr<T> * p, shared_ptr<T> * v, shared_ptr<T> w )
   435→{
   436→    sofa::pbrpc::detail::spinlock & sp = sofa::pbrpc::detail::spinlock_pool<2>::spinlock_for( p );
   437→
   438→    sp.lock();
   439→
   440→    if( p->_internal_equiv( *v ) )
   441→    {
   442→        p->swap( w );
   443→
   444→        sp.unlock();
   445→
   446→        return true;
   447→    }
   448→    else
   449→    {
   450→        shared_ptr<T> tmp( *p );
   451→
   452→        sp.unlock();
   453→
   454→        tmp.swap( *v );
   455→        return false;
   456→    }
   457→}
   458→
   459→template<class T> inline bool atomic_compare_exchange_explicit( shared_ptr<T> * p, shared_ptr<T> * v, shared_ptr<T> w, ::sofa::pbrpc::memory_order /*success*/, ::sofa::pbrpc::memory_order /*failure*/ )
   460→{
   461→    return atomic_compare_exchange( p, v, w ); // std::move( w )
   462→}
   463→
   464→// hash_value
   465→
   466→template< class T > std::size_t hash_value( sofa::pbrpc::shared_ptr<T> const & p )
   467→{
   468→    return reinterpret_cast<std::size_t>(p.get());
   469→}
   470→
   471→} // namespace pbrpc
   472→} // namespace sofa
   473→
